use std::fmt;

#[derive(Debug)]
pub enum OptionState {
    ITM,
    ATM,
    OTM,
}

impl fmt::Display for OptionState {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            OptionState::ITM => write!(f, "In-The-Money"),
            OptionState::ATM => write!(f, "At-The-Money"),
            OptionState::OTM => write!(f, "Out-Of-The-Money"),
        }
    }
}

struct OptionData {
    strike: f64,
    current_price: f64,
    state: OptionState,
}

impl OptionData {
    fn new(strike: f64, current_price: f64) -> Self {
        let state = if current_price > strike * 0.95 && current_price < strike * 1.05 {
            OptionState::ATM
        } else if current_price >= strike * 1.02 {
            OptionState::ITM
        } else {
            OptionState::OTM
        };
        OptionData { 
            strike, 
            current_price: current_price,
            state: state
        }
    }

    fn calculate_payoff(&self) -> f64 {
        match self.state {
            OptionState::ITM => (self.current_price - self.strike).max(0.0),
            OptionState::ATM => 0.0,
            OptionState::OTM => 0.0,
        }
    }
}

fn main() {
    let initial_option = OptionData::new(100.0, 110.0);
    println!("Initial State: {}", initial_option.state);
    println!("Payoff: {:.2}", initial_option.calculate_payoff());

    let deep_out_of_money = OptionData::new(50.0, 40.0);
    println!("
Deep OTM State: {}", deep_out_of_money.state);
    println!("Payoff: {:.2}", deep_out_of_money.calculate_payoff());
}

