use std::mem;

#[repr(C)]
pub enum ParticleType {
    Spark = 1,
    Smoke = 2,
    Fire = 3,
}

struct RendererData {
    particle_kind: i32,
}

impl From<ParticleType> for RendererData {
    fn from(ptype: ParticleType) -> Self {
        let kind = unsafe {
            mem::transmute::<ParticleType, i32>(ptype)
        };
        RendererData { particle_kind: kind }
    }
}

fn process_particle_effect(data: RendererData) {
    if data.particle_kind == 1 {
        println!("Rendering Spark effect based on integer ID.");
    } else if data.particle_kind == 2 {
        println!("Rendering Smoke trail using raw value.");
    } else if data.particle_kind == 3 {
        println!("Applying Fire particle logic.");
    } else {
        println!("Unknown particle type received.");
    }
}

fn main() {
    let spark = ParticleType::Spark;
    let smoke = ParticleType::Smoke;

    let render_spark = RendererData::from(spark);
    process_particle_effect(render_spark);

    let render_smoke = RendererData::from(smoke);
    process_particle_effect(render_smoke);
}

use std::fmt::{self, Display};

#[derive(Debug)]
enum HardwareMessage {
    InitSequence(u32),
    ChallengeResponse(Vec<u8>),
    StatusUpdate(String),
    Heartbeat,
}

impl Display for HardwareMessage {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            HardwareMessage::InitSequence(id) => write!(f, "Initial Sequence received with ID {}", id),
            HardwareMessage::ChallengeResponse(data) => write!(f, "Challenge response packet of size {}", data.len()),
            HardwareMessage::StatusUpdate(s) => write!(f, "Device status updated: {}", s),
            HardwareMessage::Heartbeat => write!(f, "Received regular heartbeat signal"),
        }
    }
}

fn process_message(msg: HardwareMessage) -> String {
    match msg {
        HardwareMessage::InitSequence(_) | HardwareMessage::ChallengeResponse(_) => format!("Processing sensitive key operation..."),
        HardwareMessage::StatusUpdate(_) => format!("Logging non-critical status change."),
        HardwareMessage::Heartbeat => format!("Acknowledged heartbeat."),
    }
}

fn main() {
    let msg1 = HardwareMessage::InitSequence(0xDEADBEEF);
    let msg2 = HardwareMessage::ChallengeResponse(vec![1, 2, 3]);
    let msg3 = HardwareMessage::StatusUpdate("Ready for authentication".to_string());

    println!("n--- Processing Messages ---");
    println!("Message 1: {}", process_message(msg1));
    println!("Message 2: {}", process_message(msg2));
    println!("Message 3: {}", process_message(msg3));

    let msg4 = HardwareMessage::Heartbeat;
    println!("nMessage 4: {}", process_message(msg4));
}
